('additional-maths:3-2-circles-tangents-and-normals:mcq:327f0cc5', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'mcq', 'mcq', 1, '{"question": "The ends of a diameter are \\( (-1,\\ 2) \\) and \\( (5,\\ 8) \\). What is \\( r^2 \\)?", "options": ["\\( 18 \\)", "\\( 72 \\)", "\\( 36 \\)", "\\( 6 \\)"]}'::jsonb, '{"answer": 0, "explain": "The diameter length squared is \\( 6^2 + 6^2 = 72 \\); the radius is half the diameter, so \\( r^2 = (2-(-1))^2 + (5-2)^2 = 9 + 9 = 18 \\)."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:mcq:36f9c655', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'mcq', 'mcq', 1, '{"question": "What is the centre of \\( x^2 + y^2 - 8x + 2y - 8 = 0 \\)?", "options": ["\\( (4,\\ -1) \\)", "\\( (-4,\\ 1) \\)", "\\( (8,\\ -2) \\)", "\\( (-8,\\ 2) \\)"]}'::jsonb, '{"answer": 0, "explain": "Completing the square: \\( (x-4)^2 + (y+1)^2 = 25 \\); centre \\( (4,-1) \\)."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:mcq:811c10dc', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'mcq', 'mcq', 1, '{"question": "What is the radius of \\( x^2 + y^2 - 8x + 2y - 8 = 0 \\)?", "options": ["\\( 5 \\)", "\\( 25 \\)", "\\( \\sqrt{8} \\)", "\\( 3 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( (x-4)^2 + (y+1)^2 = 16 + 1 + 8 = 25 \\), so \\( r = \\sqrt{25} = 5 \\)."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:mcq:5f9e9307', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'mcq', 'mcq', 1, '{"question": "The radius to a point of contact has gradient \\( \\tfrac{2}{3} \\). The tangent''s gradient there is:", "options": ["\\( -\\tfrac{3}{2} \\)", "\\( \\tfrac{2}{3} \\)", "\\( \\tfrac{3}{2} \\)", "\\( -\\tfrac{2}{3} \\)"]}'::jsonb, '{"answer": 0, "explain": "Tangent \\( \\perp \\) radius, so the tangent gradient is the negative reciprocal of \\( \\tfrac{2}{3} \\), namely \\( -\\tfrac{3}{2} \\)."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:mcq:e71170d5', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'mcq', 'mcq', 1, '{"question": "Which statement about the normal to a circle at a point is correct?", "options": ["It passes through the centre", "It is perpendicular to the radius", "It is the same line as the tangent", "It never meets the centre"]}'::jsonb, '{"answer": 0, "explain": "The normal lies along the radius, so it passes through the centre of the circle."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:mcq:4d9d5e18', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'mcq', 'mcq', 1, '{"question": "Substituting a line into a circle gives \\( x^2 - 6x + 9 = 0 \\). The line is:", "options": ["a tangent to the circle", "a chord cutting the circle twice", "missing the circle entirely", "a diameter of the circle"]}'::jsonb, '{"answer": 0, "explain": "\\( b^2 - 4ac = 36 - 36 = 0 \\): a repeated root, so the line touches once — a tangent."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:mcq:682a024f', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'mcq', 'mcq', 1, '{"question": "For which values of \\( k \\) is \\( y = x + k \\) a tangent to \\( x^2 + y^2 = 8 \\)?", "options": ["\\( k = \\pm 4 \\)", "\\( k = \\pm 8 \\)", "\\( k = 4 \\) only", "\\( k = \\pm 2\\sqrt{2} \\)"]}'::jsonb, '{"answer": 0, "explain": "Substituting gives \\( 2x^2 + 2kx + (k^2 - 8) = 0 \\); tangency needs \\( (2k)^2 - 8(k^2 - 8) = 0 \\Rightarrow k^2 = 16 \\Rightarrow k = \\pm 4 \\)."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:tf:212b00fd', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'tf', 'tf', 1, '{"question": "\\( (x - 2)^2 + (y - 5)^2 = 9 \\) is a circle with centre \\( (2,\\ 5) \\) and radius \\( 3 \\)."}'::jsonb, '{"answer": true, "explain": "Read the centre from the brackets and \\( r = \\sqrt{9} = 3 \\). ✓"}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:tf:438fb55f', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'tf', 'tf', 1, '{"question": "\\( (x + 4)^2 + (y - 1)^2 = 16 \\) has centre \\( (4,\\ 1) \\)."}'::jsonb, '{"answer": false, "explain": "\\( (x+4)^2 = (x-(-4))^2 \\), so the centre is \\( (-4,\\ 1) \\) — the sign flips."}'::jsonb),
('additional-maths:3-2-circles-tangents-and-normals:tf:87c7509b', 'additional-maths', 'additional-maths:3-2-circles-tangents-and-normals', '3.2 Circles, Tangents and Normals', 'tf', 'tf', 1, '{"question": "The radius of \\( (x - 1)^2 + (y - 2)^2 = 20 \\) is \\( 20 \\)."}'::jsonb, '{"answer": false, "explain": "The right-hand side is \\( r^2 \\); the radius is \\( \\sqrt{20} = 2\\sqrt{5} \\)."}'::jsonb)
